mapper.select:
SELECT 
    co.*,
    c.college_name,
    m.major_name
FROM edu_course co
LEFT JOIN edu_college c ON co.college_id = c.id
LEFT JOIN edu_major m ON co.major_id = m.id


        AND co.course_code LIKE CONCAT('%', #{courseCode}, '%')


        AND co.course_name LIKE CONCAT('%', #{courseName}, '%')


        AND co.college_id = #{collegeId}


        AND co.major_id = #{majorId}


        AND co.semester = #{semester}


        AND co.course_type = #{courseType}


        AND co.status = #{status}


ORDER BY co.id DESC

